mapper.select:
SELECT m.*
FROM private_message m
WHERE m.id IN (
    SELECT MAX(id) FROM (
        SELECT MAX(id) as id, receiver_id as friend_id
        FROM private_message
        WHERE sender_id = #{currentUserId}
        AND receiver_id IN #{id}
        AND is_recall = 0
        GROUP BY receiver_id

        UNION ALL

        SELECT MAX(id) as id, sender_id as friend_id
        FROM private_message
        WHERE receiver_id = #{currentUserId}
        AND sender_id IN #{id}
        AND is_recall = 0
        GROUP BY sender_id
    ) t GROUP BY friend_id
)
